import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.BESLAG_OP_LOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.CONTROLE_BLO_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.NETTO_KEY;

public class ControlesRekenResultaten {

    private ControlesRekenResultatenService controlesRekenResultatenService;
    private TussenkomstManager tussenkomstManager;

    public ControlesRekenResultaten(ControlesRekenResultatenService controlesRekenResultatenService, TussenkomstManager tussenkomstManager) {
        this.controlesRekenResultatenService = controlesRekenResultatenService;
        this.tussenkomstManager = tussenkomstManager;
    }

    private static final Money BOVENGRENS_NETTO = new Money(4000);
    private static final Money ONDERGRENS_NETTO = Money.ONE_EURO;

    public List<ControleAgenda> controleer(Admin admin, Persoon persoon, LocalDate beginDatum, Integer huidigFiscaalJaar, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            warnings.addAll(controleer(admin, opdracht, beginDatum, huidigFiscaalJaar, actor));
        }

        warnings.addAll(controleerOpBedrijfsvoorheffingIsZero(admin, persoon, beginDatum, actor));
        warnings.addAll(controleerBedrijfsvoorheffingBedrijfsvoorheffingEnBelastbaarPerPersoon(admin, persoon, beginDatum, huidigFiscaalJaar, actor));
        warnings.addAll(controleerOpTussenkomstenOpZeroBedragen(beginDatum, actor));
        warnings.addAll(controleerOpSleutelTussenkomstenOpZeroBedragen(beginDatum, actor));
        return warnings;
    }

    private Collection<ControleAgenda> controleerOpBedrijfsvoorheffingIsZero(Admin admin, Persoon persoon, LocalDate datum, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<ControleData4> results = controlesRekenResultatenService.bepaalControleDataBvIsZeroAndVakgOrEjt(admin, persoon, datum);
        if (!results.isEmpty()) {
            List<ControleData4> results2 = controlesRekenResultatenService.bepaalTotaalBbGewoneBezoldiging(admin, persoon, datum);
            if (results2.isEmpty()) {
                String baseWarning = "Bedrijfsvoorheffing is nul bij vakantiegeld of eindejaarstoelage.";
                List<ControleData5> akes = controlesRekenResultatenService.bepaalControleDataAkeBvIsZeroAndVakgOrEjt(admin, persoon, datum);
                Map<Integer, Opdracht> idToOpdracht = AlgemeenTools.maakIdToIdentifiableMap(persoon.getOpdrachten());
                for (ControleData5 akeData : akes) {
                    Opdracht opdracht = idToOpdracht.get(akeData.getOpdrachtId());
                    String warning = baseWarning + " ake:" + akeData.getKode() + "-" + akeData.getExt() + ", id:" + akeData.getAkeId();
                    warnings.add(maakControleAgenda(RekenControleCode.BV_IS_ZERO, opdracht, datum, warning, actor));
                }
            }
        }
        return warnings;
    }

    private Collection<ControleAgenda> controleerOpTussenkomstenOpZeroBedragen(LocalDate datum, String actor) {
        List<ControleAgenda> controles = new ArrayList<>();
        Multimap<OpdrachtAardKodeExtensieKey, MoneyKey> tussenkomstOpZeroMap = tussenkomstManager.getTussenkomstOpZeroMap();
        if (!tussenkomstOpZeroMap.isEmpty()) {
            Multimap<Opdracht, OpdrachtAardKodeExtensieKey> opdrachtToSleutelMap = HashMultimap.create();
            tussenkomstOpZeroMap.keySet().forEach(x -> opdrachtToSleutelMap.put(x.getOpdracht(), x));
            for (Opdracht opdracht : opdrachtToSleutelMap.keySet()) {
                Collection<OpdrachtAardKodeExtensieKey> sleutels = opdrachtToSleutelMap.get(opdracht);
                for (OpdrachtAardKodeExtensieKey sleutel : sleutels) {
                    Collection<MoneyKey> moneyKeys = tussenkomstOpZeroMap.get(sleutel);
                    AardKodeExtensie loonCode = sleutel.getAardKodeExtensie();
                    if (!moneyKeys.isEmpty() && !LoonCodeTools.isFictieveAkeDoelgroepVerminderingen(loonCode)) {
                        MoneyKey moneyKey = moneyKeys.iterator().next();
                        RekenBedragType bedragType = RekenTools.moneyKeyToBedragType(moneyKey);
                        StringBuilder warningBuilder = new StringBuilder("Er is een manuele tussenkomsten op 0 bedrag voor bedragtype ")
                                .append(bedragType.getLangeTekst());
                        if (moneyKeys.size() > 1) {
                            warningBuilder.append(" (en andere)");
                        }
                        warningBuilder.append(" op ").append(toAkeString(loonCode));
                        String warning = warningBuilder.toString();
                        controles.add(maakControleAgenda(RekenControleCode.TUSSENKOMST_OP_ZERO_PROPERTY, opdracht, datum, warning, actor));
                    }
                }
            }
        }
        return controles;
    }

    private Collection<ControleAgenda> controleerOpSleutelTussenkomstenOpZeroBedragen(LocalDate datum, String actor) {
        List<ControleAgenda> controles = new ArrayList<>();
        Multimap<OpdrachtAardKodeExtensieKey, MoneyKey> tussenkomstOpZeroMap = tussenkomstManager.getSleutelTussenkomstOpZeroMap();
        if (!tussenkomstOpZeroMap.isEmpty()) {
            Multimap<Opdracht, OpdrachtAardKodeExtensieKey> opdrachtToSleutelMap = HashMultimap.create();
            tussenkomstOpZeroMap.keySet().forEach(x -> opdrachtToSleutelMap.put(x.getOpdracht(), x));
            for (Opdracht opdracht : opdrachtToSleutelMap.keySet()) {
                Collection<OpdrachtAardKodeExtensieKey> sleutels = opdrachtToSleutelMap.get(opdracht);
                String warning;
                if (sleutels.size() > 1) {
                    warning = "Er zijn meerdere manuele tussenkomsten op 0 bedragen";
                    controles.add(maakControleAgenda(RekenControleCode.SLEUTEL_TUSSENKOMST_OP_ZERO_PROPERTY, opdracht, datum, warning, actor));
                } else if (sleutels.size() == 1) {
                    OpdrachtAardKodeExtensieKey sleutel = sleutels.iterator().next();
                    warning = "Er is een manuele tussenkomsten op 0 bedrag op " + toAkeString(sleutel.getAardKodeExtensie());
                    controles.add(maakControleAgenda(RekenControleCode.SLEUTEL_TUSSENKOMST_OP_ZERO_PROPERTY, opdracht, datum, warning, actor));
                }
            }
        }
        return controles;
    }

    private String toAkeString(AardKodeExtensie aardKodeExtensie) {
        return aardKodeExtensie.getTijdperk() + "-" + aardKodeExtensie.getAard() + "-" + aardKodeExtensie.getCode() + "-" + aardKodeExtensie
                .getExtensie();
    }

    public List<ControleAgenda> controleer(Admin admin, Opdracht opdracht, LocalDate beginDatum, Integer huidigFiscaalJaar, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        warnings.addAll(controleerNettoEnBruto(admin, opdracht, beginDatum, actor));
        warnings.addAll(controleerSomBrutoPerLooncode(admin, opdracht, beginDatum, actor));
        warnings.addAll(controleerSomBrutoPerLooncodePerElementairePeriode(admin, opdracht, beginDatum, actor));
        warnings.addAll(controleerRszInhoudingVersusWerkbonus(admin, opdracht, beginDatum, actor));
        warnings.addAll(controleerAanwezigheidWeddebeslagKoppeling(admin, opdracht, beginDatum, actor));
        warnings.addAll(controleerBedrijfsvoorheffingBedrijfsvoorheffingEnBelastbaarPerOpdracht(admin, opdracht, beginDatum, huidigFiscaalJaar, actor));
        return warnings;
    }

    private static final LocalDate START_CONTROLE_WEDDEBIJSLAG_KOPPELING = new LocalDate(2011, 1, 1);

    private List<ControleAgenda> controleerAanwezigheidWeddebeslagKoppeling(Admin admin, Opdracht opdracht, LocalDate datum, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        if (datum.compareTo(START_CONTROLE_WEDDEBIJSLAG_KOPPELING) >= 0 && opdracht.getHoedanigheid() == Hoedanigheid.VASTBENOEMDEN) {
            List<ControleData2> results = controlesRekenResultatenService.bepaalControleDataAanwezigheidWeddebijslagKoppeling(admin, opdracht, datum);
            for (ControleData2 result : results) {
                String warning = "Geen koppeling met weddebijslagen voorzien voor looncode " + result.getKode() + "-" + result.getExt() + ".";
                if (RekenTools.isActorInternCs(actor)) {
                    warning += " Gelieve hiervoor een topdesk aan te maken met subcategorie Dmfa-kopp.weddeschalen/bijslag.";
                } else {
                    warning += " Gelieve dit aan uw PRC of software begeleider te bezorgen.";
                }
                warnings.add(maakControleAgenda(RekenControleCode.AANWEZ_WEDDEBIJSLAG_KOPPELING, opdracht, datum, warning, actor));
            }
        }
        return warnings;
    }

    private List<ControleAgenda> controleerBedrijfsvoorheffingBedrijfsvoorheffingEnBelastbaarPerOpdracht(
            Admin admin, Opdracht opdracht,
            LocalDate datum, Integer fiscaalJaar, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<ControleData3> results = controlesRekenResultatenService.bepaalControleDataBvEnBbOverOpdrachtMaand(admin, opdracht, datum, fiscaalJaar);
        for (ControleData3 result : results) {
            MoneyMap<String> bedragen = result.getBedragen();
            Money bb = bedragen.get("bb");
            Money bv = bedragen.get("bv");
            String warning = "Controle bb en bv opdracht onbekende Case bb:" + bb + ";bv:" + bv + " contacteer Payroll & HR";
            RekenControleCode rekenControleCode = RekenControleCode.ONBEKENDE_WAARSCHUWING;
            if (bv.signum() < 0) {
                warning = "bedrijfsvoorheffing is negatief over fiscaal jaar en opdracht/maand, bv:" + bv;
                rekenControleCode = RekenControleCode.BEDRIJFSVOORHEFFING_NEGATIEF;
            } else if (bb.compareTo(bv) < 0) {
                warning = "bedrijfsvoorheffing is groter dan belastbaar over fiscaal jaar en opdracht/maand, bb:" + bb + ";bv:" + bv;
                rekenControleCode = RekenControleCode.BV_GROTER_DAN_BELASTBAAR_OPDRACHT;
            }
            warnings.add(maakControleAgenda(rekenControleCode, opdracht, datum, warning, actor));
        }
        return warnings;
    }

    private List<ControleAgenda> controleerBedrijfsvoorheffingBedrijfsvoorheffingEnBelastbaarPerPersoon(
            Admin admin, Persoon persoon, LocalDate datum,
            Integer fiscaalJaar, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<ControleData4> results = controlesRekenResultatenService.bepaalControleDataBvEnBbOverPersoonMaand(admin, persoon, datum, fiscaalJaar);
        for (ControleData4 result : results) {
            MoneyMap<String> bedragen = result.getBedragen();
            Money bb = bedragen.get("bb");
            Money bv = bedragen.get("bv");
            String warning = "Controle bb en bv persoon onbekende Case bb:" + bb + ";bv:" + bv + " contacteer Payroll & HR";
            RekenControleCode rekenControleCode = RekenControleCode.ONBEKENDE_WAARSCHUWING;
            if (bb.compareTo(bv) < 0) {
                warning = "bedrijfsvoorheffing is groter dan belastbaar over fiscaal jaar en persoon/maand, bb:" + bb + ";bv:" + bv;
                rekenControleCode = RekenControleCode.BV_GROTER_DAN_BELASTBAAR_PERSOON;
            }
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                warnings.add(maakControleAgenda(rekenControleCode, opdracht, datum, warning, actor));
            }
        }
        return warnings;
    }

    private List<ControleAgenda> controleerNettoEnBruto(Admin admin, Opdracht opdracht, LocalDate datum, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<ControleData> results = controlesRekenResultatenService.bepaalControleDataNettoEnBruto(admin, opdracht, datum);
        for (ControleData result : results) {
            MoneyMap<String> bedragen = result.getBedragen();
            Money bruto = bedragen.get("bruto");
            Money netto = bedragen.get("netto");
            String warning = "bruto:" + bruto + ";netto:" + netto;
            //het tp veld is hier opgevuld om aan te geven dat het om jaarvergoedingen gaat of niet, en dus niet met het tijdperk
            if (result.getTp() == 1) {
                warning = "jaarvergoedingen, " + warning;
            }
            RekenControleCode rekenControleCode;
            if (netto.compareTo(BOVENGRENS_NETTO) > 0) {
                rekenControleCode = RekenControleCode.NETTO_GROTER_DAN_BOVENGRENS;
                warning += ";Netto groter dan " + BOVENGRENS_NETTO;
            } else if (netto.compareTo(ONDERGRENS_NETTO) < 0) {
                rekenControleCode = RekenControleCode.NETTO_KLEINER_DAN_ONDERGRENS;
                warning += ";Netto kleiner dan " + ONDERGRENS_NETTO;
            } else if (netto.compareTo(bruto) > 0) {
                rekenControleCode = RekenControleCode.NETTO_GROTER_DAN_BRUTO;
                warning += ";Netto groter dan Bruto";
            } else {
                rekenControleCode = RekenControleCode.ONBEKENDE_WAARSCHUWING;
                warning += " contacteer Payroll & HR";
            }

            warnings.add(maakControleAgenda(rekenControleCode, opdracht, datum, warning, actor));

            if (rekenControleCode == RekenControleCode.NETTO_KLEINER_DAN_ONDERGRENS) {
                List<ControleData> inhoudingen = controlesRekenResultatenService.bepaalInhoudingen(admin, opdracht, datum);
                for (ControleData inhouding : inhoudingen) {
                    String warningInhouding =
                            "detail: " + warning + "; kode-ext: " + inhouding.getKode() + "-" + inhouding.getExt() + "; bedrag: " + inhouding
                                    .getBedragen().getMoney("netto");
                    warnings.add(maakControleAgenda(rekenControleCode, opdracht, datum, warningInhouding, actor));
                }
            }
        }
        return warnings;
    }

    private List<ControleAgenda> controleerSomBrutoPerLooncode(Admin admin, Opdracht opdracht, LocalDate datum, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<ControleData> results = controlesRekenResultatenService.bepaalControleDataSomBrutoPerLooncode(admin, opdracht, datum);
        for (ControleData result : results) {
            Money bruto = result.getBedragen().get("bruto");
            Money bassi = result.getBedragen().get("bassi");
            String warning = "tp:" + result.getTp() + "; kode:" + result.getKode() + ";bruto:" + bruto + ";bassi:" + bassi;
            RekenControleCode rekenControleCode = RekenControleCode.ONBEKENDE_WAARSCHUWING;
            if (bruto.signum() < 0) {
                rekenControleCode = RekenControleCode.BRUTO_PER_LOONCODE_KLEINER_DAN_NUL;
                warning += ";Bruto Per Looncode kleiner dan 0";
            }
            if (bassi.signum() < 0) {
                rekenControleCode = RekenControleCode.BASSI_PER_LOONCODE_KLEINER_DAN_NUL;
                warning += ";Bassi Per Looncode kleiner dan 0";
            }
            if (rekenControleCode == RekenControleCode.ONBEKENDE_WAARSCHUWING) {
                warning += " contacteer Payroll & HR";
            }

            warnings.add(maakControleAgenda(rekenControleCode, opdracht, datum, warning, actor));
        }
        return warnings;
    }

    private List<ControleAgenda> controleerSomBrutoPerLooncodePerElementairePeriode(Admin admin, Opdracht opdracht, LocalDate datum, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<ControleData> results =
                controlesRekenResultatenService.bepaalControleDataSomBrutoPerLooncodePerElementairePeriode(admin, opdracht, datum);
        for (ControleData result : results) {
            Money bruto = result.getBedragen().get("bruto");
            Money bassi = result.getBedragen().get("bassi");
            String warning =
                    "beginDatum:" + result.getBeginDatum() + "; eindDatum:" + result.getEindDatum() + "; tp:" + result.getTp() + "; kode:" + result
                            .getKode() + ";bruto:" + bruto + ";bassi:" + bassi;
            RekenControleCode rekenControleCode = RekenControleCode.ONBEKENDE_WAARSCHUWING;
            if (bruto.signum() < 0) {
                rekenControleCode = RekenControleCode.BRUTO_PER_LOONCODE_PER_ELEMENTAIRE_PERIODE_KLEINER_DAN_NUL;
                warning = warning + ";Bruto Per Looncode Per Elementaire Periode kleiner dan 0";
            }
            if (bassi.signum() < 0) {
                rekenControleCode = RekenControleCode.BASSI_PER_LOONCODE_PER_ELEMENTAIRE_PERIODE_KLEINER_DAN_NUL;
                warning = warning + ";Bassi Per Looncode Per Elementaire Periode kleiner dan 0";
            }
            if (rekenControleCode == RekenControleCode.ONBEKENDE_WAARSCHUWING) {
                warning += " contacteer Payroll & HR";
            }
            warnings.add(maakControleAgenda(rekenControleCode, opdracht, datum, warning, actor));
        }
        return warnings;
    }

    private List<ControleAgenda> controleerRszInhoudingVersusWerkbonus(Admin admin, Opdracht opdracht, LocalDate datum, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<ControleData> results = controlesRekenResultatenService.bepaalControleDataRszInhoudingVersusWerkbonus(admin, opdracht, datum);
        for (ControleData result : results) {
            Money rsz = result.getBedragen().get("rsz");
            Money werkbonus = result.getBedragen().get("werkbonus");
            String warning = "rsz:" + rsz + ";werkbonus:" + werkbonus;
            RekenControleCode rekenControleCode;
            if (rsz.compareTo(werkbonus) < 0 && werkbonus.signum() != 0) {
                rekenControleCode = RekenControleCode.WERKBONUS_GROTER_DAN_RSZ;
                warning = warning + ";Werkbonus groter dan RSZ bijdrage";
                warnings.add(maakControleAgenda(rekenControleCode, opdracht, datum, warning, actor));
            }

        }
        return warnings;
    }

    public List<ControleAgenda> controleerBeslagOpLoonMogelijksFoutBerekend(Persoon persoon, LoonElementManager manager, RekenTijd rekenTijd, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        List<AardKodeExtensie> probleemKodes = new ArrayList<>();

        boolean beslagOpLoonAanwezig = false;

        for (LoonElement element : manager.getPersoonsElementen()) {
            AardKodeExtensie loonCode = element.getAardKodeExtensie();
            if (loonCode.behoortTotGroep(BESLAG_OP_LOON_KEY) && element.getPropertyMoney(NETTO_KEY).signum() != 0) {
                beslagOpLoonAanwezig = true;
            } else if (loonCode.behoortTotGroep(CONTROLE_BLO_KEY)) {
                probleemKodes.add(loonCode);
            }
        }

        if (beslagOpLoonAanwezig && !probleemKodes.isEmpty()) {
            String akeList = probleemKodes.stream().map(x -> x.getCode() + "-" + x.getExtensie()).collect(Collectors.joining(","));
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                ControleAgenda punt = maakControleAgenda(RekenControleCode.NAZICHT_BLO, opdracht, rekenTijd.beginDatum,
                        "Nazicht beslag op loon, aanwezigheid volgende kodes " + akeList, actor);

                warnings.add(punt);
            }
        }
        return warnings;
    }

    public ControleAgenda maakControleAgenda(RekenControleCode rekenControleCode, Opdracht opdracht, LocalDate datum, String warning, String actor) {
        ControleAgenda agenda = new ControleAgendaPO();
        agenda.setWerkgever(opdracht.getWerkgever());
        agenda.setPersoon(opdracht.getPersoon());
        agenda.setOpdrachtNummer(opdracht.getOpdrachtnr());
        agenda.setBeginDatum(datum.withDayOfMonth(1));
        agenda.setEindDatum(datum.dayOfMonth().withMaximumValue());
        agenda.setRekenControleCode(rekenControleCode);
        agenda.setOpmerking(warning.replace("€", "Euro"));
        agenda.setStatus(StatusControleAgenda.OPEN);
        agenda.setActor(actor);
        return agenda;
    }

    public List<ControleAgenda> verwerkProtoWaarschuwingen(Set<ProtoControle> protoWaarschuwingen, RekenTijd rekenTijd, String actor) {
        List<ControleAgenda> warnings = new ArrayList<>();
        for (ProtoControle proto : protoWaarschuwingen) {
            ControleAgenda agenda = maakControleAgenda(proto.getControleCode(), proto.getOpdracht(), rekenTijd.beginDatum, proto.getWaarschuwing(), actor);
            warnings.add(agenda);
        }
        return warnings;
    }
}
